const body = $json.body || $json;

const nome = body.nome || '';
const email = body.email || '';
const mensagem = body.mensagem || '';

if (!nome || !email || !mensagem) {
  return [{
    json: {
      valido: false,
      erro: 'Campos obrigatórios ausentes. Envie nome, email e mensagem.',
      nome,
      email,
      mensagem
    }
  }];
}

return [{
  json: {
    valido: true,
    nome,
    email,
    mensagem: mensagem.toLowerCase(),
    mensagemOriginal: mensagem
  }
}];

const item = $json;

if (!item.valido) {
  return [{ json: item }];
}

const msg = item.mensagem;
let categoria = 'duvida_geral';
let prioridade = 'normal';

if (msg.includes('agendar') || msg.includes('agenda') || msg.includes('horário') || msg.includes('horario')) {
  categoria = 'agendamento';
  prioridade = 'alta';
}

if (msg.includes('suporte') || msg.includes('erro') || msg.includes('problema') || msg.includes('bug')) {
  categoria = 'suporte';
  prioridade = 'alta';
}

if (msg.includes('orçamento') || msg.includes('orcamento') || msg.includes('valor') || msg.includes('preço') || msg.includes('preco')) {
  categoria = 'orcamento';
  prioridade = 'media';
}

return [{
  json: {
    ...item,
    categoria,
    prioridade
  }
}];

const item = $json;

if (!item.valido) {
  return [{
    json: {
      status: 'error',
      resposta: item.erro
    }
  }];
}

let resposta = '';

switch (item.categoria) {
  case 'agendamento':
    resposta = `Olá ${item.nome}! Recebemos sua solicitação de agendamento. Nossa equipe retornará com os horários disponíveis.`;
    break;
  case 'suporte':
    resposta = `Olá ${item.nome}! Recebemos sua solicitação de suporte. Vamos analisar o problema informado e retornar com uma orientação.`;
    break;
  case 'orcamento':
    resposta = `Olá ${item.nome}! Recebemos seu pedido de orçamento. Em breve enviaremos mais informações sobre valores e disponibilidade.`;
    break;
  default:
    resposta = `Olá ${item.nome}! Recebemos sua mensagem e retornaremos em breve com mais detalhes.`;
}

return [{
  json: {
    status: 'success',
    nome: item.nome,
    email: item.email,
    categoria: item.categoria,
    prioridade: item.prioridade,
    mensagemRecebida: item.mensagemOriginal,
    resposta,
    dataAtendimento: new Date().toISOString()
  }
}];
